    // requests. GET (serverQuery) is expected to be idempotent and is not subject
    // to this check.
    if (req.method !== "GET") {
        const originCheck = validateSameOrigin(req, allowedOrigins);
        if (!originCheck.valid) {
            return originCheck.response;
        }
